def oracle(nums, target):
    n = len(nums)
    MOD = 1000000007
    count = 0
    for mask in range(1, 1 << n):
        lo = None
        hi = None
        for i in range(n):
            if mask & (1 << i):
                v = nums[i]
                if lo is None or v < lo:
                    lo = v
                if hi is None or v > hi:
                    hi = v
        if lo + hi <= target:
            count += 1
    return count % MOD

class Solution:
    def numSubseq(self, nums, target):
        return oracle(nums, target)

