class Solution:
    def numSubseq(self, nums, target):
        MOD = 1000000007
        nums = sorted(nums)
        n = len(nums)
        pow2 = [1] * n
        for i in range(1, n):
            pow2[i] = (pow2[i - 1] * 2) % MOD
        i, j = 0, n - 1
        res = 0
        while i <= j:
            if nums[i] + nums[j] <= target:
                res = (res + pow2[j - i]) % MOD
                i += 1
            else:
                j -= 1
        return res

